const items = $input.all();

// Используем Map с числовыми ключами
const channelToInstanceMap = new Map([
    // Instance 1
    [-1001481574785, 1],  // n8n Chat & Community
    [-1001355397423, 1],  // ⚡️ Запили мне, зерокодер
    [-1001368529433, 1],  // Tilda Chat & Community
    [-1001713869488, 1],  // Нейросетевые покои (перемещено из instance 2)
    [-1001227126149, 1],  // 💎 Зерокодер (перемещено из instance 2)

    // Instance 2  
    [-1001669426155, 2],  // Midjourney Chat & Community
    [-1001846101893, 2],  // ChatGPT Chat & Community
    [-1001400993706, 2],  // FlutterFlow Chat & Community
    [-1001875436239, 2],  // Supabase Chat & Community

    // Instance 3
    [-1002691668415, 3],  // n8n — Ai автоматизация
    [-1001320116679, 3],  // Directual Chat & Community
    [-1001490371259, 3],  // Webflow Chat & Community
    [-1001495935272, 3],  // Adalo Chat & Community
    [-1001493935574, 3],  // Bubble Chat & Community

    // Instance 4
    [-1002357729236, 4],  // На фрилансе 🧑‍💻
    [-1001496931309, 4],  // Airtable Chat & Community
    [-1001386345486, 4],  // GlideApps Chat & Community
    [-1001797490588, 4],  // Appsmith Chat & Community
    [-1001325600676, 4]   // Make (ex-Integromat) Chat & Community (перемещено из instance 3)
]);

// Значение по умолчанию для неизвестных чатов
const DEFAULT_INSTANCE_ID = 1;

return items.map(item => {
    // Преобразуем chat_id в число (на всякий случай)
    const chatId = Number(item.json.chat_id);

    // Ищем в Map по числовому ключу
    const instanceId = channelToInstanceMap.get(chatId) || DEFAULT_INSTANCE_ID;

    // Логирование для отладки (можно убрать в production)
    console.log(`Chat ID: ${chatId}, Instance ID: ${instanceId}`);

    return {
        json: {
            query: `
                INSERT INTO telegram_messages 
                    (chat_id, user_id, message_id, text, telegram_date, instance_id)
                VALUES ($1, $2, $3, $4, $5, $6)
                ON CONFLICT (chat_id, message_id)
                DO UPDATE SET
                    text = EXCLUDED.text,
                    telegram_date = EXCLUDED.telegram_date,
                    instance_id = EXCLUDED.instance_id,
                    llm_processed = CASE 
                        WHEN telegram_messages.text IS DISTINCT FROM EXCLUDED.text THEN 0
                        ELSE telegram_messages.llm_processed
                    END,
                    llm_is_relevant = CASE 
                        WHEN telegram_messages.text IS DISTINCT FROM EXCLUDED.text THEN NULL
                        ELSE telegram_messages.llm_is_relevant
                    END,
                    updated_at = CURRENT_TIMESTAMP
                RETURNING id;
            `,
            params: [
                chatId,                    // число
                item.json.user_id,         // число
                item.json.message_id,      // число
                item.json.text,            // строка
                item.json.telegram_date,   // строка
                instanceId                 // число
            ]
        }
    };
});

const result = [];

for (const item of $input.all()) {
  if (item.json && item.json.message) {
    const message = item.json.message;

    const chat_id = message.chat_id || null;
    const message_id = message.id || null;

    let user_id = null;
    if (message.sender_id && message.sender_id.user_id !== undefined && message.sender_id.user_id !== null) {
      user_id = message.sender_id.user_id; // ТОЛЬКО из sender_id.user_id
    }

    // Пропускаем записи без user_id
    if (user_id === null || user_id === undefined) {
      continue;
    }

    // ТОЛЬКО message.content.text.text
    let text = null;
    if (message.content && 
        message.content.text && 
        message.content.text.text && 
        typeof message.content.text.text === 'string') {
      text = message.content.text.text;
    }

    let telegram_date = null;
    if (message.date) {
      telegram_date = typeof message.date === 'number' 
        ? new Date(message.date * 1000).toISOString()
        : message.date;
    }

    // Условие: (message_id = null & chat_id = null & user_id = null) or (text = null)
    // Теперь user_id всегда не null, но оставляем проверку для других полей
    const allIdsNull = message_id === null || chat_id === null;
    if (allIdsNull || text === null) {
      continue;
    }

    const trimmedText = text.trim();
    if (trimmedText === '' || trimmedText === 'null') {
      continue;
    }

    result.push({
      chat_id,
      user_id,
      message_id,
      text: trimmedText,
      telegram_date
    });
  }
}

return result.map(item => ({ json: item }));

const items = $input.all();

if (!items.length) {
  return [];
}

function parseArray(value) {
  if (Array.isArray(value)) {
    return value;
  }

  if (typeof value === 'string') {
    const raw = value.trim();
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return raw
        .split(/[\r\n,]+/)
        .map(s => s.trim())
        .filter(Boolean);
    }
  }

  return [];
}

function normalizeArray(arr) {
  return [...new Set(
    arr
      .map(v => Number(v))
      .filter(v => Number.isFinite(v))
  )].sort((a, b) => a - b);
}

function arraysEqualAsSets(a, b) {
  if (a.length !== b.length) return false;

  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return false;
  }

  return true;
}

const searchesRaw = [];
const messages = [];

// 1) Собираем search-объекты и сообщения
for (const item of items) {
  const row = item.json ?? {};

  // Вариант, когда search'и лежат в data
  if (Array.isArray(row.data)) {
    for (const s of row.data) {
      searchesRaw.push(s);
    }
    continue;
  }

  // Запасной вариант: если search приходит отдельным item
  if (
    row.search_id !== undefined &&
    (row.regexp_chat_ids !== undefined || row.llm_chat_ids !== undefined)
  ) {
    searchesRaw.push(row);
    continue;
  }

  // Сообщения
  if (row.chat_id !== undefined && row.chat_id !== null) {
    messages.push(row);
  }
}

if (!searchesRaw.length) {
  throw new Error('Не найдены search-объекты');
}

// 2) Нормализуем все search
const searches = searchesRaw.map((search) => {
  const searchId = search.search_id ?? null;

  if (searchId === null) {
    throw new Error('У одного из search-объектов отсутствует search_id');
  }

  const regexpChatIds = normalizeArray(parseArray(search.regexp_chat_ids));
  const llmChatIds = normalizeArray(parseArray(search.llm_chat_ids));

  if (!regexpChatIds.length || !llmChatIds.length) {
    throw new Error(`Для search_id=${searchId} не найдены regexp_chat_ids и/или llm_chat_ids`);
  }

  const isCommon = arraysEqualAsSets(regexpChatIds, llmChatIds);

  if (isCommon) {
    return {
      search_id: searchId,
      scenario: 'common',
      chat_ids: regexpChatIds,
    };
  }

  return {
    search_id: searchId,
    scenario: 'split',
    regexp_chat_ids: regexpChatIds,
    llm_chat_ids: llmChatIds,
  };
});

// 3) Формируем выход:
//    - 1 служебный item со всеми search
//    - все сообщения дальше как есть
const out = [
  {
    json: {
      searches,
    },
  },
];

for (const msg of messages) {
  const chat_id = Number(msg.chat_id);
  const message_id = Number(msg.message_id);

  out.push({
    json: {
      ...msg,
      chat_id: Number.isFinite(chat_id) ? chat_id : msg.chat_id,
      message_id: Number.isFinite(message_id) ? message_id : msg.message_id,
    },
  });
}

return out;

const items = $input.all();

if (!items.length) {
  return [];
}

function parseArray(value) {
  if (Array.isArray(value)) {
    return value
      .map(v => Number(v))
      .filter(v => Number.isFinite(v));
  }

  if (typeof value === 'string') {
    const raw = value.trim();
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed
          .map(v => Number(v))
          .filter(v => Number.isFinite(v));
      }
    } catch (e) {
      return raw
        .split(/[\r\n,]+/)
        .map(s => Number(String(s).trim()))
        .filter(v => Number.isFinite(v));
    }
  }

  return [];
}

const firstRow = items[0]?.json ?? {};
const searches = Array.isArray(firstRow.searches) ? firstRow.searches : [];

if (!searches.length) {
  throw new Error('Не найден массив searches в первом item');
}

const messages = items
  .slice(1)
  .map(item => item.json ?? {})
  .filter(row => row.chat_id !== undefined && row.chat_id !== null);

const result = [];

for (const msg of messages) {
  const chat_id = Number(msg.chat_id);
  const message_id = Number(msg.message_id);

  if (!Number.isFinite(chat_id)) {
    continue;
  }

  const matchedSearchIds = [];

  for (const search of searches) {
    const searchId = Number(search.search_id);
    const scenario = search.scenario ?? null;

    if (!Number.isFinite(searchId) || !scenario) {
      continue;
    }

    let keep = false;

    if (scenario === 'common') {
      const commonSet = new Set(parseArray(search.chat_ids));
      if (commonSet.has(chat_id)) {
        keep = true;
      }
    } else if (scenario === 'split') {
      const regexpSet = new Set(parseArray(search.regexp_chat_ids));
      const llmSet = new Set(parseArray(search.llm_chat_ids));

      if (msg.regexp_relevant !== null && msg.regexp_relevant !== undefined) {
        if (regexpSet.has(chat_id)) {
          keep = true;
        }
      }

      if (msg.llm_relevant !== null && msg.llm_relevant !== undefined) {
        if (llmSet.has(chat_id)) {
          keep = true;
        }
      }
    }

    if (keep) {
      matchedSearchIds.push(searchId);
    }
  }

  if (matchedSearchIds.length > 0) {
    const uniqueMatchedSearchIds = [...new Set(matchedSearchIds)].sort((a, b) => a - b);

    result.push({
      json: {
        ...msg,
        chat_id,
        message_id: Number.isFinite(message_id) ? message_id : msg.message_id,
        matched_search_ids: uniqueMatchedSearchIds,
        matched_search_ids_csv: uniqueMatchedSearchIds.join(','),
      },
    });
  }
}

return result;

const items = $input.all();

return items.map((item) => {
  const data = item.json;
  const dbId = data.DB_id ?? data.id ?? null;

  if (dbId === null || dbId === undefined || dbId === '') {
    return {
      json: {
        error: 'Missing DB_id',
        original_data: data,
      },
    };
  }

  const query = `
    UPDATE telegram_messages
    SET
      from_db_to_sheets = $1,
      updated_at = CURRENT_TIMESTAMP
    WHERE id = $2
    RETURNING id, from_db_to_sheets, updated_at;
  `;

  const params = [
    1,
    Number(dbId),
  ];

  return {
    json: {
      query,
      params,
      action: 'mark_from_db_to_sheets',
      update_data: {
        id: Number(dbId),
        from_db_to_sheets: 1,
      },
    },
  };
});
